sp_header_footer.client_script:
api.controller = function($scope,$location, $timeout) {

    var c = this;


    /* ======================
   INITIAL STATE
====================== */

    c.notifications = [];
    c.unreadCount = 0;

    c.cart = [];
    c.cartCount = 0;

    c.showNotificationPanel = false;
    c.showCartPanel = false;

    $scope.showHelp = false;
    $scope.showMenu = false;

    /* ======================
       CART TOGGLE
    ====================== */

    c.toggleCart = function($event) {

        if ($event) $event.stopPropagation();

        c.showCartPanel = !c.showCartPanel;

        c.showNotificationPanel = false;
        $scope.showHelp = false;
        $scope.showMenu = false;

        if (c.showCartPanel) {
            c.loadCart();
        }

    };


    /* ======================
       HELP MODAL TOGGLE
    ====================== */

    $scope.toggleHelp = function() {

        $scope.showHelp = !$scope.showHelp;

        $scope.showMenu = false;

    };


    /* ======================
       PROFILE MENU TOGGLE
    ====================== */

    $scope.toggleMenu = function() {

        $scope.showMenu = !$scope.showMenu;

        $scope.showHelp = false;

    };


    /* ======================
       PROFILE NAVIGATION
    ====================== */

    $scope.openProfile = function() {
        $location.href('/datamigration?id=dm_profile');
        //  window.location.href = "/datamigration?id=dm_profile";

    };


    /* ======================
       LOGOUT
    ====================== */

    $scope.logout = function() {
        $location.href("/logout.do");
        // window.location.href = "/logout.do";

    };


    /* ======================
       LOAD CART DATA
    ====================== */

    c.loadCart = function() {

        var raw = JSON.parse(
            sessionStorage.getItem("migration_cart") || "[]"
        );

        var grouped = {};

        raw.forEach(function(item) {

            if (!grouped[item.table]) {

                grouped[item.table] = {

                    name: item.table,
                    label: item.label,
                    records: []

                };

            }

            grouped[item.table].records.push({

                number: item.number || item.sys_id,

                short_description: item.short_description || "",

                sys_id: item.sys_id

            });

        });

        c.cart = Object.keys(grouped).map(function(key) {

            return grouped[key];

        });

        c.cartCount = raw.length;

    };


    /* ======================
       LIVE CART UPDATE (SAME TAB)
    ====================== */

    window.addEventListener("cartUpdated", function() {

        $scope.$applyAsync(function() {

            c.loadCart();

        });

    });


    /* ======================
       CROSS TAB CART UPDATE
    ====================== */

    window.addEventListener("storage", function() {

        $scope.$applyAsync(function() {

            c.loadCart();

        });

    });


    /* ======================
       INITIAL CART LOAD
    ====================== */

    $timeout(function() {

        c.loadCart();

    }, 100);


    /* ======================
       OUTSIDE CLICK CLOSE
    ====================== */

    angular.element(document).on("click", function(event) {

        var insideCartModal =
            event.target.closest(".cart-modal");

        var insideCartIcon =
            event.target.closest(".cart");

        var insideNotification =
            event.target.closest(".notification-modal");

        var insideProfile =
            event.target.closest(".profile-wrapper");

        var insideHelp =
            event.target.closest(".help-modal");

        if (!insideCartModal &&
            !insideCartIcon &&
            !insideNotification &&
            !insideProfile &&
            !insideHelp) {

            $scope.$applyAsync(function() {

                c.showCartPanel = false;
                c.showNotificationPanel = false;

                $scope.showHelp = false;
                $scope.showMenu = false;

            });

        }

    });


    /* ======================
       LOAD NOTIFICATIONS
    ====================== */

    c.loadNotifications = function() {

        c.server.get({

            action: "getNotifications"

        }).then(function(response) {

            if (response.data.notifications) {

                c.notifications = response.data.notifications;

                var count = 0;

                angular.forEach(c.notifications, function(n) {

                    if (!n.read) count++;

                });

                c.unreadCount = count;

            }

        });

    };


    /* ======================
       TOGGLE NOTIFICATIONS
    ====================== */

    c.toggleNotifications = function() {

        c.showNotificationPanel = !c.showNotificationPanel;

        c.showCartPanel = false;

        $scope.showHelp = false;
        $scope.showMenu = false;

    };


    /* ======================
       MARK SINGLE READ
    ====================== */

    c.markAsRead = function(notification) {

        notification.read = true;

        if (c.unreadCount > 0)
            c.unreadCount--;

        c.server.get({

            action: "markNotificationRead",
            id: notification.id

        });

    };


    /* ======================
       MARK ALL READ
    ====================== */

    c.markAllAsRead = function() {

        angular.forEach(c.notifications, function(n) {

            n.read = true;

        });

        c.unreadCount = 0;

        c.server.get({

            action: "markAllNotificationsRead"

        });

    };


    /* ======================
       NAVIGATE TO CART PAGE
    ====================== */

    c.openCartPage = function() {

        var conn = sessionStorage.getItem("currentId");
  		$location.href("?id=dm_cart&sys_id=" + conn);


    };


    /* ======================
       AUTO REFRESH NOTIFICATIONS
    ====================== */

    function notificationPolling() {

        c.loadNotifications();

        $timeout(notificationPolling, 15000);

    }

    notificationPolling();


};

sp_header_footer.css:
*{
	outline-style:none!important;
}

.dm-header{
  height:64px;
  background:#fff;
  border-bottom:1px solid #e5e7eb;
  display:flex;
  justify-content:space-between;
  align-items:center;
  padding:0 24px;
  position:relative;
  font-family: ui-sans-serif, system-ui, sans-serif, "Apple Color Emoji", "Segoe UI Emoji", "Segoe UI Symbol", "Noto Color Emoji";
}

.dm-logo{
  display:flex;
  align-items:center;
  gap:12px;
  cursor:pointer;
  text-decoration:none;
  padding:6px 10px;
  border-radius:12px;
  transition: all 0.25s ease;
}

.dm-logo:focus,
.dm-logo:active,
.dm-logo:focus-visible {
  outline: none !important;
  box-shadow: none !important;
}

.dm-logo:hover{
 // background: rgba(17, 106, 248, 0.08);
  transform: translateY(-1px);
}

.dm-logo:hover .dm-logo-icon{
  transform: scale(1.05) rotate(-2deg);
}

.dm-logo-icon img{
  height:24px;
  width:auto;
  object-fit:contain;
}

.dm-logo-text{
  display:flex;
  flex-direction:column;
  line-height:1.1;
}

.dm-logo:hover .dm-title{
  letter-spacing:0.4px;
}

.dm-header-right{
  display:flex;
  align-items:center;
  gap:20px;
}

.dm-icon,.help{
  font-size:18px;
  display:flex;
  color:#116AF8!important;
  cursor:pointer;
  position:relative;
}

.dm-icon:hover{ color:#9bc0fc; }

.badge{
  position:absolute;
  top:-12px;
  right:-12px;
  background:#eb0017;
  color:#fff;
  font-size:12px;
  padding:2px 5px;
  border-radius:30%;
}

.profile-wrapper{
  position:relative;
  border-radius:20px;
  padding:5px;
  background-color:#f4f4f4;
  color:#000;
  display:flex;
  justify-content:center;
  align-items:center;
  gap:6px;
}

.avatar{
  width:36px;
  height:36px;
  border-radius:50%;
  background:#116AF8;
  display:flex;
  color:#fff;
  align-items:center;
  justify-content:center;
  font-weight:600;
  cursor:pointer;
}

.avatar.big{
  width:48px;
  height:48px;
}

.profile-dropdown{
  position:absolute;
  z-index:50;
  right:0;
  top:54px;
  width:100%;
  background:#fff;
  border-radius:8px;
  box-shadow:0 10px 30px rgba(0,0,0,.15);
}

.profile-info{
  padding:15px;
  display:flex;
  align-items: center;
  gap:12px;
  border-bottom:1px solid #eee;
}

.menu-item{
  padding:12px 16px;
  cursor:pointer;
}
.menu-item a{ color:tomato; }
.menu-item:hover{ background:#f3f4f6; }
.logout{ color:#dc2626; }

.help-modal{
  position:absolute;
  z-index:50;
  right:70px;
  top:76px;
  width:340px;
  background:#fff;
  border-radius:10px;
  box-shadow:0 10px 30px rgba(0,0,0,.15);
}

.help-header{
  padding:14px;
  font-weight:600;
  border-bottom:1px solid #eee;
}

.help-content{
  padding:16px;
  font-size:13px;
}

.notification-modal{
  position:absolute;
  right:40px;
  top:64px;
  width:420px;
  height:640px;
  background:#fff;
  border-radius:14px;
  box-shadow:0 25px 60px rgba(0,0,0,.18);
  display:flex;
  flex-direction:column;
  overflow:hidden;
}

.notif-header-bar{
  background:#116AF8;
  color:#fff;
  padding:20px;
  display:flex;
  justify-content:space-between;
  align-items:center;
}

.notif-header-left{
  display:flex;
  gap:12px;
  align-items:center;
}

.notif-bell-icon{ font-size:22px; }

.notif-title-main{
  font-size:20px;
  font-weight:600;
}

.notif-sub{
  font-size:13px;
  opacity:.85;
}

.notif-close{
  font-size:24px;
  cursor:pointer;
}

.notif-actions{
  padding:16px;
  border-bottom:1px solid #eee;
}

.notif-btn{
  width:100%;
  background:#f3f4f6;
  border:none;
  padding:12px;
  border-radius:10px;
  font-size:14px;
  cursor:pointer;
}

.notif-list{
  flex:1;
  overflow-y:auto;
  padding:16px;
}

.notif-card{
  position:relative;
  display:flex;
  gap:12px;
  padding:16px;
  border-radius:14px;
  margin-bottom:14px;
  border:1px solid #e5e7eb;
  background:#fff;
  cursor:pointer;
  transition:.2s;
}

.notif-card:hover{ transform:translateY(-2px); }

.notif-card.success{
  background:#ecfdf5;
  border:1px solid #22c55e;
}

.notif-card.warning{
  background:#fff7ed;
  border:1px solid #f59e0b;
}

.notif-card.danger{
  background:#fef2f2;
  border:1px solid #ef4444;
}

.notif-card.info{
  background:#eff6ff;
  border:1px solid #3b82f6;
}

.notif-icon-wrapper{
  font-size:22px;
  margin-top:2px;
}

.text-success{ color:#22c55e; }
.text-warning{ color:#f59e0b; }
.text-danger{  color:#ef4444; }
.text-info{    color:#3b82f6; }

.notif-content{ flex:1; }

.notif-card-title{ font-weight:600; }

.notif-card-msg{
  font-size:14px;
  color:#6b7280;
  margin-top:2px;
}

.notif-card-time{
  font-size:12px;
  color:#9ca3af;
  margin-top:6px;
}

.notif-dot{
  position:absolute;
  right:12px;
  top:14px;
  width:8px;
  height:8px;
  background:#116AF8;
  border-radius:50%;
}

.empty-notif{
  text-align:center;
  margin-top:60px;
  color:#9ca3af;
}

.notification-modal.right-drawer{
  position:fixed;
  top:12px;
  right:16px;
  width:420px;
  height:calc(100vh - 24px);
  background:#ffffff;
  border-radius:12px;
  box-shadow:-10px 0 40px rgba(0,0,0,.15);
  transform:translateX(120%);
  transition:transform .35s ease;
  z-index:9999;
  display:flex;
  flex-direction:column;
}

.notification-modal.right-drawer.open{ transform:translateX(0); }

.drawer-overlay{
  position:fixed;
  top:0;
  left:0;
  width:100%;
  height:100vh;
  background:rgba(0,0,0,.35);
  z-index:9998;
}

.mark-read-btn{
  display:flex;
  align-items:center;
  gap:8px;
  background:#f3f4f6;
  color:#374151;
  border:none;
  padding:10px 16px;
  border-radius:8px;
  font-size:14px;
  cursor:pointer;
  transition:all .2s ease;
}

.mark-read-btn:hover{
  background:#116AF8;
  color:#ffffff;
}

.mark-read-btn:hover svg{ stroke:#ffffff; }

.mark-read-btn:focus{
  outline:none;
  box-shadow:0 0 0 2px rgba(17, 106, 248, .25);
}

.notification-item.error{
  border:1.5px solid #ef4444;
  background:#fee2e2;
}

.notification-item.error .notification-icon{ color:#ef4444; }

.cart-overlay{
  position:fixed;
  top:0;
  left:0;
  width:100%;
  height:100vh;
  background:rgba(0,0,0,.15);
  z-index:9998;
}

.cart-modal{
  position:fixed;
  top:77px;
  right:150px;
  width:350px;
  height:360px;
  display:flex;
  flex-direction:column;
  background:#ffffff;
  border-radius:16px;
  box-shadow:0 30px 80px rgba(0,0,0,.18);
  padding:24px;
  z-index:9999;
  overflow:hidden;
}

.cart-modal-header{
  font-size:20px;
  font-weight:600;
  display:flex;
  justify-content:space-between;
  align-items:center;
  margin-bottom:16px;
}

.cart-count{
  font-size:13px;
  background:#f3f4f6;
  padding:4px 10px;
  border-radius:20px;
}

.cart-scroll-area{
  flex:1;
  overflow-y:auto;
  padding-right:4px;
}

.cart-record-container{
  display:flex;
  flex-direction:column;
  gap:16px;
}

.cart-table-group{
  width:100%;
  border:1px solid #e5e7eb;
  border-radius:12px;
  overflow:hidden;
  background:white;
}

.cart-table-header{
  display:flex;
  justify-content:space-between;
  align-items:center;
  padding:12px 16px;
  background:#f3f4f6;
  font-size:14px;
  color:#374151;
}

.cart-table-count{
  background:#116AF8;
  color:white;
  padding:4px 12px;
  border-radius:20px;
  font-size:12px;
}

.cart-record-row{
  padding:14px 16px;
  border-top:1px solid #eee;
}

.cart-record-number{
  font-weight:600;
  color:#116AF8;
  font-size:15px;
}

.cart-record-desc{
  font-size:13px;
  color:#6b7280;
  margin-top:2px;
}

.cart-action-btn{
  margin-top:16px;
  margin-left:12px;
  margin-right:12px;
  width:calc(100% - 24px);
  padding:14px;
  background:#116AF8;
  color:white;
  border:none;
  border-radius:12px;
  font-size:15px;
  font-weight:600;
  cursor:pointer;
  flex-shrink:0;
  transition:.2s ease;
}

.cart-action-btn:hover{
  background: linear-gradient(to right, #116AF8, #0A50F5);
  box-shadow: 0 10px 20px rgba(17, 106, 248, 0.3);
  transition: all 2s ease-out;
}

.cart-empty-state{
  position:absolute;
  top:50%;
  left:50%;
  transform:translate(-50%, -50%);
  display:flex;
  flex-direction:column;
  align-items:center;
  justify-content:center;
  text-align:center;
  gap:14px;
  width:100%;
  pointer-events:none;
}

.cart-empty-icon{
  width:110px;
  height:110px;
  border-radius:50%;
  background:#eef2f7;
  display:flex;
  align-items:center;
  justify-content:center;
  color:#116AF8;
}

.cart-empty-title{
  font-size:22px;
  font-weight:600;
  color:#111827;
}

.cart-modal:hover{
  outline:2px solid #116AF8;
  outline-offset:2px;
  box-shadow:
    0 35px 90px rgba(0,0,0,.22),
    0 0 0 4px rgba(17, 106, 248, .08);
}

.cart-empty-subtitle{
  font-size:14px;
  color:#6b7280;
  max-width:260px;
  line-height:1.5;
}

.user-name{
  text-transform: capitalize;
  font-weight:bold;
}

sp_header_footer.script:
(function() {

    data.dt = "";

    var user = gs.getUser();

    data.user = {

        name: user.getDisplayName(),
        sys_id: user.getID()

    };


    /* INITIALS */

    var initials = "";

    var parts = data.user.name.split(" ");

    for (var i = 0; i < parts.length; i++)
        initials += parts[i].charAt(0);

    data.user.initials = initials.substring(0, 2).toUpperCase();


    /* GET NOTIFICATIONS */

    if (input && input.action == "getNotifications") {

        data.notifications = [];

        var notif = new GlideRecordSecure("x_sysus_tracenow_notifications");

        notif.addQuery("user", gs.getUserID());

        notif.orderByDesc("sys_created_on");

        notif.setLimit(20);

        notif.query();

        while (notif.next()) {

            data.notifications.push({

                id: notif.getUniqueValue(),
                title: notif.getValue("title"),
                message: notif.getValue("message"),
                priority: notif.getValue("priority"),
                read: notif.getValue("read") == true,
                time: notif.getDisplayValue("sys_created_on")

            });

        }

        return;

    }


    /* MARK SINGLE */

    if (input && input.action == "markNotificationRead") {

        var rec = new GlideRecordSecure("x_sysus_tracenow_notifications");

        if (rec.get(input.id)) {

            rec.read = true;
            rec.update();

        }

        return;

    }


    /* MARK ALL */

    if (input && input.action == "markAllNotificationsRead") {

        var recAll = new GlideRecordSecure("x_sysus_tracenow_notifications");

        recAll.addQuery("user", gs.getUserID());

        recAll.addQuery("read", false);

        recAll.query();

        while (recAll.next()) {

            recAll.read = true;
            recAll.update();

        }

        return;

    }


    /* DEMO FALLBACK */

    data.notifications = [];

    var gr = new GlideRecordSecure("sys_journal_field");

    gr.addQuery("sys_created_by", user.getName());

    gr.orderByDesc("sys_created_on");

    gr.setLimit(5);

    gr.query();

    while (gr.next()) {

        data.notifications.push({

            title: gr.getValue("value"),
            time: gr.getDisplayValue("sys_created_on")

        });

    }

})();
